            let offset = isize::from_le_bytes(buffer.as_slice().try_into().unwrap());
            if offset > file_in.size().try_into().unwrap() {
                return Ok(0);
            }
            if offset < 0 {
                return Ok(-1);
            }
            (Some(offset), Some(buffer))
        }
