        let mut byte_buffer = ByteBuffer::new(&mut buffer[..to_read]);
        let read_bytes = match input_offset {
            Some(offset) => {
                file_in
                    .read(&mut byte_buffer, Some(offset as usize + total_copied))
                    .await?
            }
            None => file_in.read(&mut byte_buffer, None).await?,
        };
        if read_bytes == 0 {
            break;
        }

