use super::{access::AsMemoryBlock, page_alloc::GlobalPageAlloc, MemoryBlock, PhysAccess};
use crate::io::{Buffer, FillResult};
use eonix_mm::paging::{Page as GenericPage, PageAlloc};

pub type Page = GenericPage<GlobalPageAlloc>;

/// A buffer that wraps a page and provides a `Buffer` interface.
pub struct PageBuffer {
    page: Page,
    offset: usize,
}

pub trait AllocZeroed {
    fn zeroed() -> Self;
}

impl<A: PageAlloc> AsMemoryBlock for GenericPage<A> {
    fn as_memblk(&self) -> MemoryBlock {
        unsafe {
            // SAFETY: `self.start()` points to valid memory of length `self.len()`.
            MemoryBlock::new(self.start().as_ptr::<()>().addr(), self.len())
        }
    }
}

impl PageBuffer {
    pub fn new() -> Self {
        Self {
            page: Page::alloc(),
            offset: 0,
        }
    }

    pub fn all(&self) -> &[u8] {
        unsafe {
            // SAFETY: The page is exclusivly owned by us.
            self.page.as_memblk().as_bytes()
        }
    }

    pub fn data(&self) -> &[u8] {
        &self.all()[..self.offset]
    }

    pub fn available_mut(&mut self) -> &mut [u8] {
        unsafe {
            // SAFETY: The page is exclusivly owned by us.
            &mut self.page.as_memblk().as_bytes_mut()[self.offset..]
        }
    }
}

impl Buffer for PageBuffer {
    fn total(&self) -> usize {
        self.page.len()
    }

    fn wrote(&self) -> usize {
        self.offset
    }

    fn fill(&mut self, data: &[u8]) -> crate::KResult<crate::io::FillResult> {
        let available = self.available_mut();
        if available.len() == 0 {
            return Ok(FillResult::Full);
        }

        let len = core::cmp::min(data.len(), available.len());
        available[..len].copy_from_slice(&data[..len]);
        self.offset += len;

        if len < data.len() {
            Ok(FillResult::Partial(len))
        } else {
            Ok(FillResult::Done(len))
        }
    }
}

impl AllocZeroed for Page {
    fn zeroed() -> Self {
        let page = Self::alloc();
        unsafe {
            // SAFETY: The page is exclusivly owned by us.
            page.as_memblk().as_bytes_mut().fill(0);
        }
        page
    }
}

use super::page_alloc::RawPagePtr;
use super::{AsMemoryBlock, GlobalPageAlloc, Page};
use core::alloc::{GlobalAlloc, Layout};
use core::ptr::NonNull;
use eonix_hal::mm::ArchPhysAccess;
use eonix_mm::address::PhysAccess;
use eonix_mm::paging::{PAGE_SIZE_BITS, PFN};
use eonix_sync::LazyLock;
use slab_allocator::SlabAllocator;

static SLAB_ALLOCATOR: LazyLock<SlabAllocator<RawPagePtr, GlobalPageAlloc, 9>> =
    LazyLock::new(|| SlabAllocator::new_in(GlobalPageAlloc));

struct Allocator;

unsafe impl GlobalAlloc for Allocator {
    unsafe fn alloc(&self, layout: Layout) -> *mut u8 {
        let size = layout.size().next_power_of_two();

        let result = if size <= 2048 {
            SLAB_ALLOCATOR.alloc(size)
        } else {
            let page_count = size >> PAGE_SIZE_BITS;
            let page = Page::alloc_at_least(page_count);

            let ptr = page.as_memblk().as_ptr();
            page.into_raw();

            ptr.as_ptr()
        };

        if result.is_null() {
            core::ptr::null_mut()
        } else {
            result as *mut u8
        }
    }

    unsafe fn dealloc(&self, ptr: *mut u8, layout: Layout) {
        let size = layout.size().next_power_of_two();

        if size <= 2048 {
            SLAB_ALLOCATOR.dealloc(ptr, size)
        } else {
            let paddr = ArchPhysAccess::from_ptr(NonNull::new_unchecked(ptr));
            let pfn = PFN::from(paddr);
            Page::from_raw(pfn);
        };
    }
}

#[global_allocator]
static ALLOCATOR: Allocator = Allocator;

# Eonix OS 内核项目深度技术分析报告

## 一、项目概述

Eonix 是一个使用 Rust 编写的多架构宏内核操作系统，支持 x86_64、RISC-V 64 和 LoongArch64 三种架构。项目采用 Rust async/await 语法实现有栈/无栈异步任务管理，具有原创内核架构设计。代码总量约 39,447 行 Rust 代码（248 个源文件），使用 `nightly-2025-05-20` 工具链，依赖大量 nightly 特性。

---

## 二、项目构建与测试

### 2.1 构建尝试

项目通过 `./configure` 脚本检测工具链并生成 `Makefile.real`，然后通过 `make` 编译。构建流程包括：
- 检测 Rust 工具链版本
- 检测 QEMU、GDB 等工具
- 生成架构特定的 Makefile

由于项目依赖特定的磁盘镜像制作流程（需要 `fdisk` 等工具创建分区表），且需要预编译的用户空间程序（busybox、init 等），完整构建和运行测试在当前环境下受限。

### 2.2 代码静态分析

通过详细的源码审查，确认项目结构完整，各子系统实现清晰，代码质量较高。

---

## 三、子系统详细分析

### 3.1 硬件抽象层（HAL）

**实现完整度：90%**

#### 3.1.1 架构支持

HAL 层位于 `crates/eonix_hal/`，提供架构无关的抽象接口，同时包含三种架构的具体实现：

**x86_64 架构实现：**
- **Bootstrap**：自定义 MBR 引导程序，从 16 位实模式 → 32 位保护模式 → 64 位长模式
- **GDT**：全局描述符表管理
- **中断处理**：完整的 IDT 设置，支持 256 个中断向量
- **FPU**：SSE/AVX 支持
- **内存管理**：4 级页表（PML4），支持 1GB 大页

**RISC-V 64 架构实现：**
- **Bootstrap**：基于 OpenSBI/RustSBI 的启动流程
- **Sv48 页表**：4 级页表支持
- **中断**：PLIC 中断控制器支持
- **定时器**：基于 SBI 的定时器

**LoongArch64 架构实现：**
- **Bootstrap**：基于 FDT（Flattened Device Tree）的启动
- **页表**：LoongArch 特定的页表格式
- **中断**：LoongArch 中断控制器支持

#### 3.1.2 关键代码分析

**x86_64 Bootstrap（`crates/eonix_hal/src/arch/x86_64/bootstrap.rs`）：**

```rust
// 16位实模式引导代码
global_asm!(
    r#"
    .pushsection .mbr, "ax", @progbits
    .code16
    .globl move_mbr
    move_mbr:
        xor %ax, %ax
        mov %ax, %ds
        mov %ax, %es
        mov %ax, %ss
        # 移动 MBR 到 0xe00
        mov $128, %cx
        mov $0x7c00, %si
        mov $0x0e00, %di
        rep movsl
        ljmp $0x0, $2f
    ...
    "#
);
```

该代码实现了完整的 BIOS 引导流程：
1. 从 0x7c00 移动 MBR 到 0x0e00
2. 使用 INT 13h 读取内核镜像
3. 使用 INT 15h E820 获取内存映射
4. 切换到保护模式
5. 设置页表并进入长模式

**SMP 多核启动：**

```rust
// AP（Application Processor）启动代码
global_asm!(
    r#"
    .pushsection .stage1.smp, "ax", @progbits
    .code16
    ljmp $0x0, $2f
    2:
    lgdt {early_gdt_descriptor}
    mov $0xc0000080, %ecx
    rdmsr
    or $0x901, %eax  # 设置 LME, NXE, SCE
    wrmsr
    ...
    "#
);
```

通过 ACPI 表获取处理器信息，使用 INIT-SIPI-SIPI 序列启动 AP。

